var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그래서, 이번엔 무슨 일인데? 미리 말해 두지만 주인님이란 호칭은 절-대 안 쓸 거니까.","JPN":"それで、今度は何の用？言っとくけど、ご主人様なんて、ぜーったいに呼ばないんだから。","ENG":"So, what is it this time? If it's about calling you Master, forget it; it's never going to happen.","TWN":"所以，這次又是什麼事？先說好了，我不會使用主人這個稱呼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"응? 내 손가락?","JPN":"え？私の指？","ENG":"Huh? My finger?","TWN":"嗯？我的手指？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그, 그냥 식칼에 살짝 긁힌 것뿐이야. 쓸데없이 치료하지 않아도 돼.","JPN":"ちょ、ちょっと包丁で切っただけよ。手当とかしなくていいから。","ENG":"I-it's just a scratch from a kitchen knife. It doesn't need any treatment.","TWN":"沒、沒什麼。只是被菜刀割了一下，不需要治療的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐, 그렇게 안달하면 반창고 붙이는 것 정돈 허락해 줄까......","JPN":"まあ、そこまで言うなら\\n絆創膏ぐらいは貼ってくれてもいいけど……","ENG":"Well, if you're so worried, I guess I can let you put a bandage on it.","TWN":"嗯，既然你這麼擔心，那我就允許你給我貼個OK繃之類的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"크흠, 흠. 고마워. 이런 거 안 붙여도 금방 나았겠지만.","JPN":"こほん、ふん。ありがとう。\\nこんなの貼らなくても、すぐ治るとは思うけど。","ENG":"*Kahem, hem* Thank you... although this wasn't necessary.","TWN":"咳嗯，謝謝。其實不用貼這些也會馬上恢復。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......그런데 너, 배는 안 고파? 늘 이 시간에 밥해 달라고 했잖아.","JPN":"…で、あんた、お腹は空いてないの？いつもこの時間にご飯作ってって言うじゃない。","ENG":"By the way, aren't you hungry yet? You usually ask me for food around this time.","TWN":"……不過你，你不餓嗎？你不是每到這個時候都會喊著要吃飯嗎。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"좋아. 그럼 여기서......","JPN":"よし、じゃあここで……","ENG":"Okay, then here...","TWN":"好，那就……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"응? 같이 먹자고?","JPN":"うん？一緒に食べようって？","ENG":" Huh? You want to eat with me?","TWN":" 嗯？一起吃？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"주, 주인 주제에 그게 메이드한테 할 소리야? 우리가 무슨 커플인 줄 착각하나 본데 절대 아니거든?!","JPN":"しゅ、主人のくせにメイドに何言ってるの？私たちがカップルか何かと勘違いしているようだけど、全然違うからね？","ENG":"A-are you out of your mind? I'm not your girlfriend—I'm your maid!","TWN":"主、主人怎麼能和女僕說這些話？你以為我們是情侶關係嗎？絕對不是！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"물론 네가 상냥하게 대해 주는 건 고맙고, 허구한 날 봐서 낯가림도 없고, 챙겨 주는 대로 잘 먹으니까......","JPN":"もちろん、あんたが優しくしてくれるのはありがたいし、いつも会ってるから慣れてるし、ご飯作るとちゃんと食べてくれるから……","ENG":"Of course, I'm grateful for your kindness. I don't feel uncomfortable around you either; I've been seeing you so often. You also like everything I cook, so...","TWN":"你對我很溫柔，我很感謝，我做的東西你也都愛吃……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"나도...... 뿌듯하긴 하지만......","JPN":"私も……嬉しいけど……","ENG":"I'm happy, but...","TWN":"我……我也很高興……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아, 아차~ 벌써 간식시간이네~ 모네 굶어 죽기 전에 얼른 가봐야겠다~","JPN":"あ、し、しまった～もうおやつの時間か。モネが飢え死にする前に早く行かないと～。","ENG":"Uh-oh, is it already snack time? I'd better go to Mone before she passes out from hunger!","TWN":"啊，哎呀~ 該吃零食了~ 我得趕緊去看看莫妮~"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어? 나한테 용건? 그 계약서 때문에 그래?","JPN":"え？私に用事？その契約書の話なの？","ENG":"Huh, a talk? For what, that contract?","TWN":"嗯？找我有事？是因為那個合約嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"자, 사인! 됐지? 보나마나 뭐 근로보험이나 계약연장 같은 거잖아?","JPN":"はい、サイン！これでいい？どうせ勤労保険とか、契約延長みたいなもんでしょ？","ENG":"There, I signed it. It's just about my unemployment insurance or employment contract extension, right?","TWN":"好，簽名！可以了吧？想來又是勞動保險或延長期限之類的吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"종신계약? ......뭐어어어어?!!","JPN":"終身契約？……はああああ！！？","ENG":"WHAT? A LIFETIME CONTRACT?!","TWN":"終身雇傭？……什麼啊啊啊啊？！！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"저기, 무르기...... 안되겠지?","JPN":"あの、取消……ってわけにはいかないわよね？","ENG":"Hey, erm... Can I back out?","TWN":"那個，能不能……反悔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"크읏....... 됐어! 까짓 거 하면 될 거 아냐! 계약은 계약이니까!","JPN":"くうっ……もういい！やればいいんでしょ？契約は契約なんだから！","ENG":"Hmpf, fine! I'll do it! A contract is a contract.","TWN":"切……算了！不就是終身雇傭嗎！合約就是合約，沒什麼的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"이렇게 된 이상, 전속 메이드로서 평생 먹여주고 돌봐줄 테니까 각오하라고. 흥!","JPN":"こうなった以上、専属メイドとして一生面倒を見るから覚悟しなさい。ふん！","ENG":"As your maid, I'll take care of you for the rest of your life. You'd better not regret this. Hmpf!","TWN":"既然這樣，那我就作為你的專屬女僕照顧你一輩子，等著瞧，哼！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};